11	// JSONLBackend stores beads as newline-delimited JSON in a single file under
12	// a .ddx directory. It is the storage shape used by Store's built-in path and
13	// is also the fallback ExternalBackend reaches for when bd/br cannot serve a
14	// non-default collection (e.g. "beads-archive"). Constructed directly only
15	// when a Backend value is needed standalone — Store's inline path predates
16	// this type and continues to operate on the same file format.
17	type JSONLBackend struct {
18		Dir      string
19		File     string
20		LockDir  string
21		LockWait time.Duration
22	}
23	
24	// NewJSONLBackend constructs a JSONL-backed Backend rooted at dir. file and
25	// lockDir must be absolute (or rooted under dir) and are written/locked
26	// directly. lockWait bounds how long WithLock spins before giving up.
27	func NewJSONLBackend(dir, file, lockDir string, lockWait time.Duration) *JSONLBackend {
28		return &JSONLBackend{Dir: dir, File: file, LockDir: lockDir, LockWait: lockWait}
29	}
30	
31	func (j *JSONLBackend) Init() error {
32		if err := os.MkdirAll(j.Dir, 0o755); err != nil {
33			return fmt.Errorf("bead: init dir: %w", err)
34		}
35		f, err := os.OpenFile(j.File, os.O_CREATE|os.O_WRONLY, 0o644)
36		if err != nil {
37			return fmt.Errorf("bead: init file: %w", err)
38		}
39		return f.Close()
40	}
41	
42	func (j *JSONLBackend) ReadAll() ([]Bead, error) {
43		data, err := os.ReadFile(j.File)
44		if os.IsNotExist(err) {
45			return nil, nil
46		}
47		if err != nil {
48			return nil, fmt.Errorf("bead: read %s: %w", j.File, err)
49		}
50		beads, _, err := parseBeadJSONL(data)
51		if err != nil {
52			return nil, fmt.Errorf("bead: parse %s: %w", j.File, err)
53		}
54		return foldLatestBeads(beads), nil
55	}
56	
57	func (j *JSONLBackend) WriteAll(beads []Bead) error {
58		sort.Slice(beads, func(a, b int) bool { return beads[a].ID < beads[b].ID })
59		if err := os.MkdirAll(j.Dir, 0o755); err != nil {
60			return fmt.Errorf("bead: mkdir: %w", err)
61		}
62		var buf []byte
63		for _, b := range beads {
64			data, err := marshalBead(b)
65			if err != nil {
66				return fmt.Errorf("bead: marshal: %w", err)
67			}
68			buf = append(buf, data...)
69			buf = append(buf, '\n')
70		}
71		return writeAtomicFile(j.File, buf)
72	}
73	
74	func (j *JSONLBackend) WithLock(fn func() error) error {
75		wait := j.LockWait
76		if wait <= 0 {
77			wait = 10 * time.Second
78		}
79		if err := acquireDirLock(j.Dir, j.LockDir, wait); err != nil {
80			return err
81		}
82		defer os.RemoveAll(j.LockDir)
83		return fn()
84	}
85	
86	// jsonlFallbackForCollection builds a JSONLBackend for the given collection
87	// rooted at ddxDir, using the default registry's spec to resolve file/lock
88	// paths. Used by the external backend when bd/br cannot serve a non-default
89	// collection through their CLI surface.
90	func jsonlFallbackForCollection(ddxDir, collection string, lockWait time.Duration) *JSONLBackend {
91		spec := DefaultRegistry().Resolve(CollectionID(collection))
92		file, lockDir := spec.PathsUnder(ddxDir)
93		// Defensive — Resolve should always return non-empty names, but guard
94		// against an empty CollectionID by computing a conventional pair.
95		if file == ddxDir || lockDir == ddxDir {
96			file = filepath.Join(ddxDir, collection+".jsonl")
97			lockDir = filepath.Join(ddxDir, collection+".lock")
98		}
99		return NewJSONLBackend(ddxDir, file, lockDir, lockWait)
100	}
