1	package bead
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os/exec"
7		"strings"
8	)
9	
10	// ExternalBackend delegates storage to an external tool (bd or br).
11	//
12	// bd and br today have no per-collection scoping in their CLI surface — `bd
13	// list --json` and `bd import` always operate on the tool's primary store.
14	// To preserve the bd/br interchange contract for the default "beads"
15	// collection AND give callers a working path for non-default collections
16	// (notably "beads-archive"), ExternalBackend may carry a JSONL fallback
17	// that handles the read/write/lock plumbing for any collection the tool
18	// cannot natively serve. The default collection always routes through the
19	// external tool; non-default collections route through the fallback when
20	// one is present.
21	type ExternalBackend struct {
22		Tool       string // "bd" or "br"
23		Collection string
24		// fallback handles all Init/Read/Write/Lock calls when set. Populated
25		// by NewExternalBackendWithFallback for non-default collections; nil
26		// for the default collection so the external tool stays authoritative.
27		fallback Backend
28	}
29	
30	// NewExternalBackend creates a backend that shells out to the given tool.
31	func NewExternalBackend(tool, collection string) (*ExternalBackend, error) {
32		if _, err := exec.LookPath(tool); err != nil {
33			return nil, fmt.Errorf("bead: backend %s not found in PATH", tool)
34		}
35		return &ExternalBackend{Tool: tool, Collection: collection}, nil
36	}
37	
38	// NewExternalBackendWithFallback constructs an external backend that routes
39	// non-default collections through the supplied fallback Backend. fallback is
40	// ignored for the default collection so the bd/br interchange path stays
41	// unchanged. fallback may be nil when the caller knows the collection is the
42	// default; callers handling arbitrary collections should always supply one.
43	func NewExternalBackendWithFallback(tool, collection string, fallback Backend) (*ExternalBackend, error) {
44		e, err := NewExternalBackend(tool, collection)
45		if err != nil {
46			return nil, err
47		}
48		if collection != DefaultCollection {
49			e.fallback = fallback
50		}
51		return e, nil
52	}
53	
54	// Init is a no-op for external backends — they manage their own storage.
55	// The fallback (when set) initializes its JSONL file and lock dir on demand.
56	func (e *ExternalBackend) Init() error {
57		if e.fallback != nil {
58			return e.fallback.Init()
59		}
60		return nil
61	}
62	
63	// ReadAll lists all beads from the external tool.
64	func (e *ExternalBackend) ReadAll() ([]Bead, error) {
65		if e.fallback != nil {
66			return e.fallback.ReadAll()
67		}
68		cmd := exec.Command(e.Tool, "list", "--json")
69		output, err := cmd.Output()
70		if err != nil {
71			return nil, fmt.Errorf("bead: %s list --json: %w", e.Tool, err)
72		}
73	
74		trimmed := strings.TrimSpace(string(output))
75		if trimmed == "" || trimmed == "[]" {
76			return nil, nil
77		}
78	
79		// Try JSON array first
80		if strings.HasPrefix(trimmed, "[") {
81			var raw []json.RawMessage
82			if err := json.Unmarshal([]byte(trimmed), &raw); err != nil {
83				return nil, fmt.Errorf("bead: %s parse: %w", e.Tool, err)
84			}
85			var beads []Bead
86			for _, r := range raw {
87				b, err := unmarshalBead(r)
88				if err != nil {
89					continue
90				}
91				beads = append(beads, b)
92			}
93			return beads, nil
94		}
95	
96		// JSONL fallback
97		var beads []Bead
98		for _, line := range strings.Split(trimmed, "\n") {
99			line = strings.TrimSpace(line)
100			if line == "" {
101				continue
102			}
103			b, err := unmarshalBead([]byte(line))
104			if err != nil {
105				continue
106			}
107			beads = append(beads, b)
108		}
109		return beads, nil
110	}
111	
112	// WriteAll writes all beads back via the external tool.
113	// For bd/br, we export as JSONL and import. This is a full replace.
114	func (e *ExternalBackend) WriteAll(beads []Bead) error {
115		if e.fallback != nil {
116			return e.fallback.WriteAll(beads)
117		}
118		// Build JSONL
119		var sb strings.Builder
120		for _, b := range beads {
121			data, err := marshalBead(b)
122			if err != nil {
123				return fmt.Errorf("bead: marshal for %s: %w", e.Tool, err)
124			}
125			sb.Write(data)
126			sb.WriteByte('\n')
127		}
128	
129		// Pipe to tool's import command
130		cmd := exec.Command(e.Tool, "import", "--from", "jsonl", "--replace", "-")
131		cmd.Stdin = strings.NewReader(sb.String())
132		if output, err := cmd.CombinedOutput(); err != nil {
133			return fmt.Errorf("bead: %s import: %s: %w", e.Tool, string(output), err)
134		}
135		return nil
136	}
137	
138	// WithLock for external backends is a no-op — the tool handles its own
139	// locking. When a JSONL fallback is in play we delegate locking to it so
140	// concurrent writers serialize on the fallback file's lock dir.
141	func (e *ExternalBackend) WithLock(fn func() error) error {
142		if e.fallback != nil {
143			return e.fallback.WithLock(fn)
144		}
145		return fn()
146	}
