435	// Create adds a new bead. Assigns defaults, validates, then persists.
436	func (s *Store) Create(b *Bead) error {
437		now := time.Now().UTC()
438		if b.ID == "" {
439			id, err := s.GenID()
440			if err != nil {
441				return err
442			}
443			b.ID = id
444		}
445		if b.IssueType == "" {
446			b.IssueType = DefaultType
447		}
448		if b.Status == "" {
449			b.Status = DefaultStatus
450		}
451		b.CreatedAt = now
452		b.UpdatedAt = now
453	
454		// Validate after defaults are applied so hooks see final state
455		if err := s.validateBead(b); err != nil {
456			return err
457		}
458		// Story 15: an operator-prompt bead's execution may not create another
459		// operator-prompt bead. The execute-bead harness exports the actor's
460		// issue_type via DDX_ACTOR_ISSUE_TYPE; absent the env, the guard is a
461		// no-op (e.g. direct CLI use by a human operator).
462		if err := OperatorPromptMutationGuard(os.Getenv("DDX_ACTOR_ISSUE_TYPE"), b.IssueType); err != nil {
463			return err
464		}
465		// Run create hook
466		if err := s.runHook("validate-bead-create", b); err != nil {
467			return err
468		}
469	
470		return s.WithLock(func() error {
471			beads, _, err := s.readAllLatestRaw()
472			if err != nil {
473				return err
474			}
475			// Reject duplicate IDs
476			for _, e := range beads {
477				if e.ID == b.ID {
478					return fmt.Errorf("bead: duplicate id: %s", b.ID)
479				}
480			}
481			// Validate deps reference existing beads
482			depIDs := b.DepIDs()
483			if len(depIDs) > 0 {
484				existing := make(map[string]bool)
485				for _, e := range beads {
486					existing[e.ID] = true
487				}
488				for _, dep := range depIDs {
489					if !existing[dep] {
490						return fmt.Errorf("bead: dependency not found: %s", dep)
491					}
492				}
493			}
494			beads = append(beads, *b)
495			return s.WriteAll(beads)
496		})
497	}
