513	// Update modifies a bead by ID. The mutate function receives a pointer to modify.
514	func (s *Store) Update(id string, mutate func(*Bead)) error {
515		return s.WithLock(func() error {
516			beads, _, err := s.readAllLatestRaw()
517			if err != nil {
518				return err
519			}
520			found := false
521			for i := range beads {
522				if beads[i].ID == id {
523					mutate(&beads[i])
524					beads[i].UpdatedAt = time.Now().UTC()
525					// Core validation after mutation
526					if err := s.validateBead(&beads[i]); err != nil {
527						return err
528					}
529					// Run update hook
530					if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
531						return err
532					}
533					found = true
534					break
535				}
536			}
537			if !found {
538				return fmt.Errorf("bead: not found: %s", id)
539			}
540			return s.WriteAll(beads)
541		})
542	}
