544	// HeartbeatInterval is how often a claim owner should refresh
545	// execute-loop-heartbeat-at while running. Exposed as a variable so tests
546	// can override it.
547	var HeartbeatInterval = 30 * time.Second
548	
549	// HeartbeatTTL is the maximum allowed age of execute-loop-heartbeat-at
550	// before another worker may reclaim the bead. Defaults to 3× HeartbeatInterval.
551	// Exposed as a variable so tests can override it.
552	var HeartbeatTTL = 90 * time.Second
553	
554	// Claim sets a bead to in_progress with claim metadata.
555	// Fails if the bead is already claimed (status == in_progress) with a
556	// fresh heartbeat. A bead whose execute-loop-heartbeat-at is older than
557	// HeartbeatTTL is considered stalled and will be reclaimed atomically.
558	func (s *Store) Claim(id, assignee string) error {
559		return s.ClaimWithOptions(id, assignee, "", "")
560	}
561	
562	// ClaimWithOptions sets a bead to in_progress with extended claim metadata.
563	// session and worktree are optional; machine is derived from os.Hostname().
564	// A stalled in_progress bead (heartbeat older than HeartbeatTTL) is reclaimed
565	// atomically under the store's lock.
566	func (s *Store) ClaimWithOptions(id, assignee, session, worktree string) error {
567		machine, _ := os.Hostname()
568		if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
569			machine = envID
570		}
571		return s.WithLock(func() error {
572			beads, _, err := s.readAllLatestRaw()
573			if err != nil {
574				return err
575			}
576			for i := range beads {
577				if beads[i].ID != id {
578					continue
579				}
580				switch beads[i].Status {
581				case StatusOpen:
582					// normal claim path
583				case StatusInProgress:
584					if !heartbeatIsStale(beads[i].Extra) {
585						return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
586					}
587					// stalled claim — reclaim atomically below
588				default:
589					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
590				}
591				// Refuse claims on beads parked with last_status=push_failed:
592				// the previous attempt landed locally but `git push` was rejected,
593				// so the local commit history exists only on this machine. Re-running
594				// primary work would duplicate or strand commits. The operator must
595				// clear execute-loop-last-status (e.g. by manually pushing or
596				// resetting) before another attempt is allowed.
597				if last, ok := beads[i].Extra["execute-loop-last-status"].(string); ok && last == "push_failed" {
598					detail, _ := beads[i].Extra["execute-loop-last-detail"].(string)
599					if detail != "" {
600						return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed (%s); clear execute-loop-last-status to retry", id, detail)
601					}
602					return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed; clear execute-loop-last-status to retry", id)
603				}
604				if beads[i].Extra == nil {
605					beads[i].Extra = make(map[string]any)
606				}
607				now := time.Now().UTC()
608				beads[i].Status = StatusInProgress
609				beads[i].Owner = assignee
610				beads[i].UpdatedAt = now
611				beads[i].Extra["claimed-at"] = now.Format(time.RFC3339)
612				beads[i].Extra["claimed-pid"] = fmt.Sprintf("%d", os.Getpid())
613				beads[i].Extra["execute-loop-heartbeat-at"] = now.Format(time.RFC3339Nano)
614				if machine != "" {
615					beads[i].Extra["claimed-machine"] = machine
616				}
617				if session != "" {
618					beads[i].Extra["claimed-session"] = session
619				}
620				if worktree != "" {
621					beads[i].Extra["claimed-worktree"] = worktree
622				}
623				if err := s.validateBead(&beads[i]); err != nil {
624					return err
625				}
626				if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
627					return err
628				}
629				return s.WriteAll(beads)
630			}
631			return fmt.Errorf("bead: not found: %s", id)
632		})
633	}
