635	// Heartbeat refreshes execute-loop-heartbeat-at on a claimed bead. Returns
636	// an error if the bead is no longer in_progress (e.g., reclaimed by another
637	// worker), allowing the caller to stop its heartbeat loop.
638	func (s *Store) Heartbeat(id string) error {
639		return s.WithLock(func() error {
640			beads, _, err := s.readAllLatestRaw()
641			if err != nil {
642				return err
643			}
644			for i := range beads {
645				if beads[i].ID != id {
646					continue
647				}
648				if beads[i].Status != StatusInProgress {
649					return fmt.Errorf("bead: cannot heartbeat %s from status %s", id, beads[i].Status)
650				}
651				if beads[i].Extra == nil {
652					beads[i].Extra = make(map[string]any)
653				}
654				beads[i].Extra["execute-loop-heartbeat-at"] = time.Now().UTC().Format(time.RFC3339Nano)
655				beads[i].UpdatedAt = time.Now().UTC()
656				return s.WriteAll(beads)
657			}
658			return fmt.Errorf("bead: not found: %s", id)
659		})
660	}
