662	// heartbeatIsStale returns true if the given bead's Extra map has no
663	// execute-loop-heartbeat-at or one older than HeartbeatTTL.
664	func heartbeatIsStale(extra map[string]any) bool {
665		if extra == nil {
666			return true
667		}
668		raw, ok := extra["execute-loop-heartbeat-at"]
669		if !ok {
670			return true
671		}
672		s, ok := raw.(string)
673		if !ok || s == "" {
674			return true
675		}
676		t, err := time.Parse(time.RFC3339Nano, s)
677		if err != nil {
678			// Fall back to RFC3339 for compatibility with legacy entries written
679			// before sub-second resolution. RFC3339Nano is the current canonical
680			// format used by both ClaimWithOptions and Heartbeat write sites.
681			t, err = time.Parse(time.RFC3339, s)
682			if err != nil {
683				return true
684			}
685		}
686		return time.Since(t) > HeartbeatTTL
687	}
