723	// IncrNoChangesCount increments the execute-loop no-changes counter for a bead
724	// and returns the new count. Used by the execute-bead worker to detect when a
725	// bead should be auto-closed after repeated no-change attempts.
726	func (s *Store) IncrNoChangesCount(id string) (int, error) {
727		var newCount int
728		err := s.Update(id, func(b *Bead) {
729			if b.Extra == nil {
730				b.Extra = make(map[string]any)
731			}
732			var count int
733			if v, ok := b.Extra["execute-loop-no-changes-count"]; ok {
734				switch n := v.(type) {
735				case int:
736					count = n
737				case float64:
738					count = int(n)
739				case int64:
740					count = int(n)
741				}
742			}
743			count++
744			b.Extra["execute-loop-no-changes-count"] = count
745			newCount = count
746		})
747		return newCount, err
