750	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
751	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
752	// DDx-authored beads always round-trip through `bd import`. Empirically
753	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
754	const MaxFieldBytes = 65535
755	
756	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
757	// need to preserve the full payload should persist it to a sidecar artifact
758	// and store a path reference in the field; this function is the defense-in-
759	// depth cap for code paths that don't. Returns the input unchanged when it
760	// fits; otherwise returns head+tail truncation with a byte-count marker.
761	func capFieldBytes(s string) string {
762		if len(s) <= MaxFieldBytes {
763			return s
764		}
765		// Reserve a marker that always fits; keep head heavy (2/3) so
766		// human-readable context is preserved for the common short-rationale case.
767		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
768		budget := MaxFieldBytes - len(marker)
769		if budget <= 0 {
770			return s[:MaxFieldBytes]
771		}
772		head := (budget * 2) / 3
773		tail := budget - head
774		return s[:head] + marker + s[len(s)-tail:]
775	}
