777	func (s *Store) AppendEvent(id string, event BeadEvent) error {
778		if event.CreatedAt.IsZero() {
779			event.CreatedAt = time.Now().UTC()
780		}
781		// Defense in depth: cap every event body regardless of caller. The
782		// reviewer write path separately persists the full stream to an artifact
783		// and emits a <=512-byte body; this cap catches anything else.
784		event.Body = capFieldBytes(event.Body)
785		event.Summary = capFieldBytes(event.Summary)
786		// Two storage shapes are possible here: inline Extra["events"] for active
787		// beads, and a sidecar attachment for closed/archived beads (ADR-004
788		// attachment model). When the bead has been externalized we append to the
789		// sidecar and leave the row untouched aside from updated_at.
790		var appendedToAttachment bool
791		if err := s.Update(id, func(b *Bead) {
792			if b.Extra == nil {
793				b.Extra = make(map[string]any)
794			}
795			if hasEventsAttachment(b) {
796				appendedToAttachment = true
797				return
798			}
799			var events []BeadEvent
800			if raw, ok := b.Extra["events"]; ok {
801				events = decodeBeadEvents(raw)
802			}
803			events = append(events, event)
804			b.Extra["events"] = encodeEventsForExtra(events)
805		}); err != nil {
806			return err
807		}
808		if !appendedToAttachment {
809			return nil
810		}
811		// Append to the sidecar under the store lock so concurrent readers and
812		// writers see a consistent events log.
813		return s.WithLock(func() error {
814			existing, err := s.readEventsAttachment(id)
815			if err != nil {
816				return err
817			}
818			existing = append(existing, event)
819			return s.writeEventsAttachment(id, existing)
820		})
821	}
822	
823	// Events returns the bead's evidence history in insertion order. Reads are
824	// transparent across storage shapes: inline Extra["events"] for active beads,
825	// or the externalized sidecar referenced by Extra[events_attachment] once the
826	// bead has been closed.
827	func (s *Store) Events(id string) ([]BeadEvent, error) {
828		b, err := s.Get(id)
829		if err != nil {
830			return nil, err
831		}
832		events, err := s.eventsForBead(b)
833		if err != nil {
834			return nil, err
835		}
836		if len(events) == 0 {
837			return []BeadEvent{}, nil
838		}
839		out := make([]BeadEvent, len(events))
840		copy(out, events)
841		return out, nil
842	}
843	
844	// EventsByKind returns all events for a bead filtered by kind, in insertion order.
845	func (s *Store) EventsByKind(id, kind string) ([]BeadEvent, error) {
846		all, err := s.Events(id)
847		if err != nil {
848			return nil, err
849		}
850		out := make([]BeadEvent, 0, len(all))
851		for _, e := range all {
852			if e.Kind == kind {
853				out = append(out, e)
854			}
855		}
856		return out, nil
857	}
858	
859	func decodeBeadEvents(raw any) []BeadEvent {
860		switch v := raw.(type) {
861		case []BeadEvent:
862			out := make([]BeadEvent, len(v))
863			copy(out, v)
864			return out
865		case []any:
866			out := make([]BeadEvent, 0, len(v))
867			for _, item := range v {
868				m, ok := item.(map[string]any)
869				if !ok {
870					continue
871				}
872				out = append(out, beadEventFromMap(m))
873			}
874			return out
875		case []map[string]any:
876			out := make([]BeadEvent, 0, len(v))
877			for _, item := range v {
878				out = append(out, beadEventFromMap(item))
879			}
880			return out
881		default:
882			return nil
883		}
884	}
885	
886	func beadEventFromMap(m map[string]any) BeadEvent {
887		e := BeadEvent{}
888		if v, ok := m["kind"].(string); ok {
889			e.Kind = v
890		}
891		if v, ok := m["summary"].(string); ok {
892			e.Summary = v
893		}
894		if v, ok := m["body"].(string); ok {
895			e.Body = v
896		}
897		if v, ok := m["actor"].(string); ok {
898			e.Actor = v
899		}
900		if v, ok := m["source"].(string); ok {
901			e.Source = v
902		}
903		if v, ok := m["created_at"].(string); ok {
904			if parsed, err := time.Parse(time.RFC3339, v); err == nil {
905				e.CreatedAt = parsed
906			}
907		}
908		return e
909	}
