911	// Close sets a bead's status to closed. When the close succeeds and the bead
912	// carries an inline event history, those events are moved to a sidecar
913	// attachment under .ddx/attachments/<id>/events.jsonl so the active row stays
914	// small (per ADR-004's attachment model and TD-027 §c).
915	func (s *Store) Close(id string) error {
916		if err := s.Update(id, func(b *Bead) {
917			b.Status = StatusClosed
918		}); err != nil {
919			return err
920		}
921		if err := s.externalizeEvents(id); err != nil {
922			return err
923		}
924		s.maybeOpportunisticArchive()
925		return nil
926	}
