928	// externalizeEvents moves a bead's inline events into its sidecar attachment
929	// under a fresh lock. Safe to call repeatedly — no-op when there are no
930	// inline events (already externalized, or none recorded).
931	func (s *Store) externalizeEvents(id string) error {
932		return s.WithLock(func() error {
933			beads, _, err := s.readAllLatestRaw()
934			if err != nil {
935				return err
936			}
937			for i := range beads {
938				if beads[i].ID != id {
939					continue
940				}
941				if err := s.externalizeEventsInPlace(&beads[i]); err != nil {
942					return err
943				}
944				return s.WriteAll(beads)
945			}
946			return nil
947		})
948	}
