950	// ErrClosureGateRejected indicates a close was refused because the bead does
951	// not carry the evidence required for an automated closure: a terminal
952	// verdict event (review APPROVE with non-empty rationale, or an explicit
953	// review-skipped / manual-close marker) AND an execution-evidence marker
954	// (closing_commit_sha, session_id, or an execute-bead success event in the
955	// events history).
956	//
957	// Automated execute-loop paths (execute-bead + reviewer) always go through
958	// CloseWithEvidence. The plain Store.Close remains as the manual
959	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
960	// acceptance §1).
961	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
962	
963	// ClosureGate inspects a bead and returns nil iff the close is safe. It
964	// rejects only the specific shapes that caused the 2026-04-18/20
965	// review-malfunction incidents:
966	//
967	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
968	//     closing_commit_sha. Rejected by the execution-evidence check —
969	//     closing_commit_sha must be non-empty OR at least one event must exist.
970	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
971	//     body is empty. Rejected — APPROVE with no rationale is exactly the
972	//     parse-mis-extract shape the reviewer bug produced.
973	//
974	// Beads without a review step (--no-review, no Reviewer configured, already-
975	// satisfied paths) pass the gate as long as they carry execution evidence.
976	// This keeps the surface small: the gate catches known-bad shapes, not every
977	// conceivable edge case. Additional invariants belong in future dedicated
978	// beads so the rejection reason stays auditable.
979	func ClosureGate(b *Bead) error {
980		if b == nil {
981			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
982		}
983		hasClosingCommit := false
984		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
985			hasClosingCommit = true
986		}
987		events := decodeBeadEvents(b.Extra["events"])
988		// Externalized events still count as evidence for the gate. We only need
989		// to know whether *some* event history exists, not iterate it; the
990		// gate's APPROVE-with-empty-rationale check below relies on inline events
991		// (the verdict is recorded before externalization).
992		hasAttachedEvents := hasEventsAttachment(b)
993		// Reject the axon-c5cc071a shape: no events AND no closing commit.
994		if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
995			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
996		}
997		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
998		for _, e := range events {
999			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
1000				if strings.TrimSpace(e.Body) == "" {
1001					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
1002				}
1003			}
1004		}
1005		return nil
1006	}
