1008	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
1009	// sessionID is the agent session that completed the work.
1010	// commitSHA is the exact closing commit SHA when it is known.
1011	//
1012	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
1013	// via this path without a terminal verdict event plus execution evidence.
1014	// Store.Close is the manual-administration escape hatch when the gate is
1015	// inappropriate.
1016	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
1017		if err := s.closeWithEvidence(id, sessionID, commitSHA); err != nil {
1018			return err
1019		}
1020		// Externalize events only when the gate actually transitioned the bead
1021		// to closed; rejected closes leave the bead open and inline.
1022		if b, err := s.Get(id); err == nil && b != nil && b.Status == StatusClosed {
1023			if err := s.externalizeEvents(id); err != nil {
1024				return err
1025			}
1026		}
1027		s.maybeOpportunisticArchive()
1028		return nil
1029	}
