1031	func (s *Store) closeWithEvidence(id string, sessionID string, commitSHA string) error {
1032		return s.Update(id, func(b *Bead) {
1033			if b.Extra == nil {
1034				b.Extra = make(map[string]any)
1035			}
1036			if sessionID != "" {
1037				b.Extra["session_id"] = sessionID
1038			}
1039			if commitSHA != "" {
1040				b.Extra["closing_commit_sha"] = commitSHA
1041			}
1042			if err := ClosureGate(b); err != nil {
1043				// Surface via bead notes so a later operator audit can see why the
1044				// close was refused; a single error path would be dropped by the
1045				// Update callback signature (no error return).
1046				appendClosureRejectNote(b, err)
1047				return
1048			}
1049			b.Status = StatusClosed
1050		})
1051	}
