1078	// Reopen sets a bead's status back to open, clears claim fields, optionally
1079	// appends notes, and records an immutable reopen event — all in one atomic
1080	// lock acquisition.
1081	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
1082		now := time.Now().UTC()
1083		return s.WithLock(func() error {
1084			beads, _, err := s.readAllLatestRaw()
1085			if err != nil {
1086				return err
1087			}
1088			found := false
1089			for i := range beads {
1090				if beads[i].ID != id {
1091					continue
1092				}
1093				b := &beads[i]
1094				b.Status = StatusOpen
1095				b.Owner = ""
1096				b.UpdatedAt = now
1097				if b.Extra == nil {
1098					b.Extra = make(map[string]any)
1099				}
1100				// Clear claim fields
1101				delete(b.Extra, "claimed-at")
1102				delete(b.Extra, "claimed-pid")
1103				delete(b.Extra, "claimed-machine")
1104				delete(b.Extra, "claimed-session")
1105				delete(b.Extra, "claimed-worktree")
1106				delete(b.Extra, "execute-loop-heartbeat-at")
1107				// Append notes
1108				if appendNotes != "" {
1109					if b.Notes != "" {
1110						b.Notes = b.Notes + "\n\n" + appendNotes
1111					} else {
1112						b.Notes = appendNotes
1113					}
1114				}
1115				// Record reopen event. If events were externalized at close,
1116				// pull them back inline so the active row carries the full
1117				// history again and the attachment ref is dropped.
1118				if hasEventsAttachment(b) {
1119					if err := s.inlineEventsInPlace(b); err != nil {
1120						return err
1121					}
1122					_ = os.Remove(s.eventsAttachmentPath(b.ID))
1123				}
1124				var events []BeadEvent
1125				if raw, ok := b.Extra["events"]; ok {
1126					events = decodeBeadEvents(raw)
1127				}
1128				evt := BeadEvent{
1129					Kind:      "reopen",
1130					CreatedAt: now,
1131				}
1132				if reason != "" {
1133					evt.Summary = reason
1134				}
1135				events = append(events, evt)
1136				encoded := make([]map[string]any, 0, len(events))
1137				for _, e := range events {
1138					encoded = append(encoded, map[string]any{
1139						"kind":       e.Kind,
1140						"summary":    e.Summary,
1141						"body":       e.Body,
1142						"actor":      e.Actor,
1143						"created_at": e.CreatedAt,
1144						"source":     e.Source,
1145					})
1146				}
1147				b.Extra["events"] = encoded
1148				if err := s.validateBead(b); err != nil {
1149					return err
1150				}
1151				if err := s.runHook("validate-bead-update", b); err != nil {
1152					return err
1153				}
1154				found = true
1155				break
1156			}
1157			if !found {
1158				return fmt.Errorf("bead: not found: %s", id)
1159			}
1160			return s.WriteAll(beads)
1161		})
1162	}
