1197	// matchesWhere returns true if the bead satisfies all key=value predicates.
1198	// It checks known struct fields first, then falls back to Extra.
1199	func matchesWhere(b Bead, where map[string]string) bool {
1200		for k, v := range where {
1201			var actual string
1202			switch k {
1203			case "id":
1204				actual = b.ID
1205			case "title":
1206				actual = b.Title
1207			case "status":
1208				actual = b.Status
1209			case "issue_type":
1210				actual = b.IssueType
1211			case "owner":
1212				actual = b.Owner
1213			case "assignee":
1214				actual = b.Owner
1215			case "parent":
1216				actual = b.Parent
1217			case "description":
1218				actual = b.Description
1219			case "acceptance":
1220				actual = b.Acceptance
1221			case "notes":
1222				actual = b.Notes
1223			default:
1224				// Fall back to Extra map for unknown/workflow-specific fields
1225				if b.Extra != nil {
1226					if ev, ok := b.Extra[k]; ok {
1227						actual = fmt.Sprintf("%v", ev)
1228					}
1229				}
1230			}
1231			if actual != v {
1232				return false
1233			}
1234		}
1235		return true
1236	}
