1250	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1251	// they are NOT execution-eligible: epic containers, retry cooldown,
1252	// execution-eligible=false, or superseded. It's the diagnostic the work loop
1253	// emits when the execution queue is empty but `ddx bead ready` is not.
1254	type ReadyExecutionBreakdown struct {
1255		SkippedEpics       []string
1256		SkippedOnCooldown  []string
1257		SkippedNotEligible []string
1258		SkippedSuperseded  []string
1259		NextRetryAfter     string
1260	}
1261	
1262	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1263		out := ReadyExecutionBreakdown{}
1264		ready, err := s.Ready()
1265		if err != nil {
1266			return out, err
1267		}
1268		now := time.Now().UTC()
1269		var soonestRetry time.Time
1270		for _, b := range ready {
1271			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1272				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1273					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1274						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1275						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1276							soonestRetry = retryAfter
1277						}
1278						continue
1279					}
1280				}
1281			}
1282			if eligible, ok := b.Extra["execution-eligible"]; ok {
1283				if val, isBool := eligible.(bool); isBool && !val {
1284					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1285					continue
1286				}
1287			}
1288			if sup, ok := b.Extra["superseded-by"]; ok {
1289				if s, isStr := sup.(string); isStr && s != "" {
1290					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1291					continue
1292				}
1293			}
1294		}
1295		if !soonestRetry.IsZero() {
1296			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1297		}
1298		return out, nil
1299	}
