1301	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1302		beads, err := s.ReadAll()
1303		if err != nil {
1304			return nil, err
1305		}
1306		statusMap := make(map[string]string)
1307		for _, b := range beads {
1308			statusMap[b.ID] = b.Status
1309		}
1310	
1311		var ready []Bead
1312		for _, b := range beads {
1313			if b.Status != StatusOpen {
1314				// Surface stalled in_progress beads so a fresh worker can
1315				// reclaim them atomically in Claim().
1316				if executionOnly && b.Status == StatusInProgress && heartbeatIsStale(b.Extra) {
1317					// fall through to dependency check below
1318				} else {
1319					continue
1320				}
1321			}
1322			allSatisfied := true
1323			for _, depID := range b.DepIDs() {
1324				if statusMap[depID] != StatusClosed {
1325					allSatisfied = false
1326					break
1327				}
1328			}
1329			if !allSatisfied {
1330				continue
1331			}
1332			if executionOnly {
1333				// Filter by execution-eligible (default true if absent)
1334				eligible, ok := b.Extra["execution-eligible"]
1335				if ok {
1336					if val, isBool := eligible.(bool); isBool && !val {
1337						continue
1338					}
1339				}
1340				// Filter out superseded beads
1341				if sup, ok := b.Extra["superseded-by"]; ok {
1342					if s, isStr := sup.(string); isStr && s != "" {
1343						continue
1344					}
1345				}
1346				if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1347					if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1348						if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
1349							continue
1350						}
1351					}
1352				}
1353			}
1354			ready = append(ready, b)
1355		}
1356	
1357		sortBeadsForQueue(ready)
1358	
1359		return ready, nil
1360	}
