1362	// Blocked returns open beads with at least one unclosed dependency.
1363	func (s *Store) Blocked() ([]Bead, error) {
1364		beads, err := s.ReadAll()
1365		if err != nil {
1366			return nil, err
1367		}
1368		statusMap := make(map[string]string)
1369		for _, b := range beads {
1370			statusMap[b.ID] = b.Status
1371		}
1372	
1373		var blocked []Bead
1374		for _, b := range beads {
1375			if b.Status != StatusOpen {
1376				continue
1377			}
1378			for _, depID := range b.DepIDs() {
1379				if statusMap[depID] != StatusClosed {
1380					blocked = append(blocked, b)
1381					break
1382				}
1383			}
1384		}
1385		sortBeadsForQueue(blocked)
1386		return blocked, nil
1387	}
