1389	// BlockedAll returns open beads that are currently not runnable, classified
1390	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1391	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1392	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1393	// that is both dep-blocked and cooldown-parked is reported as dependency-
1394	// blocked, because deps are the stronger blocker.
1395	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1396		beads, err := s.ReadAll()
1397		if err != nil {
1398			return nil, err
1399		}
1400		statusMap := make(map[string]string)
1401		for _, b := range beads {
1402			statusMap[b.ID] = b.Status
1403		}
1404	
1405		now := time.Now().UTC()
1406		var entries []BlockedBead
1407		for _, b := range beads {
1408			if b.Status != StatusOpen {
1409				continue
1410			}
1411	
1412			var unclosed []string
1413			for _, depID := range b.DepIDs() {
1414				if statusMap[depID] != StatusClosed {
1415					unclosed = append(unclosed, depID)
1416				}
1417			}
1418			if len(unclosed) > 0 {
1419				entries = append(entries, BlockedBead{
1420					Bead: b,
1421					Blocker: Blocker{
1422						Kind:           BlockerKindDependency,
1423						UnclosedDepIDs: unclosed,
1424					},
1425				})
1426				continue
1427			}
1428	
1429			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1430			if !ok {
1431				continue
1432			}
1433			retryAfterStr, isStr := retryAfterRaw.(string)
1434			if !isStr || retryAfterStr == "" {
1435				continue
1436			}
1437			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1438			if err != nil || !retryAfter.After(now) {
1439				continue
1440			}
1441			blocker := Blocker{
1442				Kind:           BlockerKindRetryCooldown,
1443				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1444			}
1445			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1446				if s, ok := v.(string); ok {
1447					blocker.LastStatus = s
1448				}
1449			}
1450			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1451				if s, ok := v.(string); ok {
1452					blocker.LastDetail = s
1453				}
1454			}
1455			entries = append(entries, BlockedBead{
1456				Bead:    b,
1457				Blocker: blocker,
1458			})
1459		}
1460	
1461		sort.SliceStable(entries, func(i, j int) bool {
1462			if entries[i].Priority != entries[j].Priority {
1463				return entries[i].Priority < entries[j].Priority
1464			}
1465			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1466				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1467			}
1468			return entries[i].ID < entries[j].ID
1469		})
1470		return entries, nil
1471	}
1472	
1473	func sortBeadsForQueue(beads []Bead) {
1474		sort.SliceStable(beads, func(i, j int) bool {
1475			if beads[i].Priority != beads[j].Priority {
1476				return beads[i].Priority < beads[j].Priority
1477			}
1478			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1479				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1480			}
1481			return beads[i].ID < beads[j].ID
1482		})
1483	}
