1485	// Status returns aggregate counts.
1486	func (s *Store) Status() (*StatusCounts, error) {
1487		beads, err := s.ReadAll()
1488		if err != nil {
1489			return nil, err
1490		}
1491		ready, err := s.Ready()
1492		if err != nil {
1493			return nil, err
1494		}
1495		blocked, err := s.Blocked()
1496		if err != nil {
1497			return nil, err
1498		}
1499	
1500		// Pull in archive partner so totals survive `bead migrate` — the archive
1501		// only carries closed beads, so Ready/Blocked aren't affected.
1502		seen := make(map[string]bool, len(beads))
1503		all := make([]Bead, 0, len(beads))
1504		for _, b := range beads {
1505			if seen[b.ID] {
1506				continue
1507			}
1508			seen[b.ID] = true
1509			all = append(all, b)
1510		}
1511		if s.Collection == DefaultCollection {
1512			archive := s.archivePartner()
1513			if archived, aerr := archive.ReadAll(); aerr == nil {
1514				for _, b := range archived {
1515					if seen[b.ID] {
1516						continue
1517					}
1518					seen[b.ID] = true
1519					all = append(all, b)
1520				}
1521			}
1522		}
1523	
1524		counts := &StatusCounts{Total: len(all), Ready: len(ready), Blocked: len(blocked)}
1525		for _, b := range all {
1526			switch b.Status {
1527			case StatusOpen:
1528				counts.Open++
1529			case StatusClosed:
1530				counts.Closed++
1531			}
1532		}
1533		return counts, nil
1534	}
