1536	// DepAdd adds a dependency: id depends on depID.
1537	func (s *Store) DepAdd(id, depID string) error {
1538		return s.WithLock(func() error {
1539			beads, _, err := s.readAllLatestRaw()
1540			if err != nil {
1541				return err
1542			}
1543			var target *Bead
1544			depExists := false
1545			for i := range beads {
1546				if beads[i].ID == id {
1547					target = &beads[i]
1548				}
1549				if beads[i].ID == depID {
1550					depExists = true
1551				}
1552			}
1553			if target == nil {
1554				return fmt.Errorf("bead: not found: %s", id)
1555			}
1556			if !depExists {
1557				return fmt.Errorf("bead: dependency not found: %s", depID)
1558			}
1559			if id == depID {
1560				return fmt.Errorf("bead: cannot depend on self")
1561			}
1562			if target.HasDep(depID) {
1563				return nil // already exists
1564			}
1565	
1566			// Check for circular dependency
1567			depMap := make(map[string][]string)
1568			for _, b := range beads {
1569				depMap[b.ID] = b.DepIDs()
1570			}
1571			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
1572			if hasCycle(depMap, id) {
1573				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
1574			}
1575	
1576			target.AddDep(depID, "blocks")
1577			target.UpdatedAt = time.Now().UTC()
1578			return s.WriteAll(beads)
1579		})
1580	}
