1589	// DepTree returns a text representation of the dependency tree.
1590	func (s *Store) DepTree(rootID string) (string, error) {
1591		beads, err := s.ReadAll()
1592		if err != nil {
1593			return "", err
1594		}
1595		// Pull in archive partner so the tree survives `bead migrate` — closed
1596		// beads stored only in the archive must still appear.
1597		if s.Collection == DefaultCollection {
1598			archive := s.archivePartner()
1599			if archived, aerr := archive.ReadAll(); aerr == nil {
1600				seen := make(map[string]bool, len(beads))
1601				for _, b := range beads {
1602					seen[b.ID] = true
1603				}
1604				for _, b := range archived {
1605					if seen[b.ID] {
1606						continue
1607					}
